2	\chapter{Sheaves of \(k\)-modules: sheafification, Ext, and the structure sheaf as a sheaf of \(k\)-modules}
3	\label{chap:Cohomology_StructureSheafModuleK}
4	
5	This chapter implements Phase~A step~5: equipping \(H^1(C, \mathcal O_C)\) with a \(k\)-vector-space structure when \(C\) is a scheme over \(\Spec k\). The route is through the linear enrichment of the sheaf category over \(k\), which automatically provides a \(k\)-module structure on \(\Ext\) groups in any \(k\)-linear abelian category. The chapter introduces no protected declarations: every instance and definition here is auxiliary, supporting the construction of \(H^1(C, \mathcal O_C)\) in Definition~REF.
6	
7	The chapter splits into two parts. Sections~REF--REF provide the typeclass plumbing: sheafification and \(\Ext\) for sheaves valued in \(k\)-modules. Section~REF provides the substantive content: the \(k\)-module-valued structure sheaf for a scheme over \(\Spec k\), built from the algebra map induced by the structure morphism. Together these complete Phase~A step~5; the final remaining piece for an honest definition of genus is Phase~A step~6 (Serre finiteness, multi-iteration).
8	
9	\section{Sheafification of \(k\)-module-valued sheaves on opens}
10	\label{sec:moduleK_prereqs}
11	
12	\begin{theorem}\leanok
13	[Sheafification on the topology of opens, \(k\)-module valued]
14	  \label{thm:HasSheafify_Opens_ModuleCatK}
15	  \lean{AlgebraicGeometry.Cohomology.instHasSheafify_Opens_ModuleCatK}
16	  Let \(k\) be a commutative ring and \(X\) a topological space. Then the Grothendieck topology of opens of \(X\) admits sheafification for sheaves valued in the category of \(k\)-modules.
17	\end{theorem}
18	
19	\begin{proof}
20	
21	
22	\leanok
23	  Mathlib's general sheafification API constructs sheafification whenever weak sheafification holds and the resulting sheafification preserves finite limits. For the topology of opens and the category of \(k\)-modules, both prerequisites are available in Mathlib. The instance is therefore inferable; the formal task is the universe pinning, mirroring the abelian-group analogue (Theorem~REF).
24	\end{proof}
25	
26	\section{\(\Ext\) for \(k\)-module-valued sheaves on opens}
27	\label{sec:moduleK_ext}
28	
29	\begin{theorem}\leanok
30	[\(\Ext\) on the topology of opens, \(k\)-module valued]
31	  \label{thm:HasExt_Sheaf_Opens_ModuleCatK}
32	  \lean{AlgebraicGeometry.Cohomology.instHasExt_Sheaf_Opens_ModuleCatK}
33	  \uses{thm:HasSheafify_Opens_ModuleCatK}
34	
35	  Let \(k\) be a commutative ring and \(X\) a topological space. Then the category of sheaves of \(k\)-modules on the topology of opens of \(X\) admits \(\Ext\) groups.
36	\end{theorem}
37	
38	\begin{proof}
39	
40	
41	\leanok
42	  The category of \(k\)-modules is abelian. The sheaf category inherits an abelian structure from an abelian value category once sheafification is available (Theorem~REF). Mathlib's standard construction produces \(\Ext\) from any abelian category. The universe annotation matches the morphism universe of the sheaf category, mirroring the abelian-group analogue (Theorem~REF).
43	\end{proof}
44	
45	\section{The structure sheaf of a \(\Spec k\)-scheme as a sheaf of \(k\)-modules}
46	\label{sec:scheme_toModuleKSheaf}
47	
48	This section provides the substantive content of Phase~A step~5. For \(C\) a scheme over \(\Spec k\), the structure morphism \(C \to \Spec k\) induces an algebra map \(k \to \Gamma(C, U)\) for every open \(U \subseteq C\). This equips the structure sheaf with a sheaf-of-\(k\)-modules structure.
49	
50	\subsection{The algebra map from the structure morphism}
51	
52	For each open \(U \subseteq C\), the structure morphism induces a chain of ring maps
53	\[
54	  k \xrightarrow{\cong} \Gamma(\Spec k, \top) \xrightarrow{C.\mathrm{hom}} \Gamma(C, C.\mathrm{hom}^{-1}\top) \xrightarrow{\rho} \Gamma(C, U),
55	\]
56	where \(\rho\) is the restriction along \(U \le C.\mathrm{hom}^{-1}\top = \top\).
57	
58	\begin{definition}\leanok
59	[Algebra map on a section]
60	  \label{def:Scheme_kToSection}
61	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.kToSection}
62	  
63	  Let \(k\) be a commutative ring and \(C\) a scheme over \(\Spec k\). For any open \(U\) of \(C\), define the ring map \(k \to \Gamma(C, U)\) to be the composition of the inverse of the canonical isomorphism \(\Gamma(\Spec k, \top) \cong k\), the structure morphism map on global sections, and the restriction from \(\top\) to \(U\).
64	\end{definition}
65	
66	\begin{definition}\leanok
67	[Algebra structure on a section]
68	  \label{def:Scheme_algebraSection}
69	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.algebraSection}
70	  \uses{def:Scheme_kToSection}
71	
72	  The ring map of Definition~REF exhibits \(\Gamma(C, U)\) as a \(k\)-algebra.
73	\end{definition}
74	
75	\begin{lemma}\leanok
76	[Defining identity for the algebra map]
77	  \label{lem:Scheme_algebraMap_eq_kToSection}
78	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.algebraMap_eq_kToSection}
79	  \uses{def:Scheme_algebraSection, def:Scheme_kToSection}
80	
81	  Under the algebra structure of Definition~REF, the structure map \(k \to \Gamma(C, U)\) equals the ring map of Definition~REF.
82	\end{lemma}
83	
84	\begin{proof}
85	  
86	  \leanok
87	  Definitionally true: converting a ring homomorphism to an algebra structure and extracting the structure map recovers the original homomorphism.
88	\end{proof}
89	
90	\subsection{Naturality of the algebra map}
91	
92	\begin{lemma}\leanok
93	[Restriction is compatible with the algebra map]
94	  \label{lem:Scheme_kToSection_naturality}
95	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.kToSection_naturality}
96	  \uses{def:Scheme_kToSection}
97	
98	  For any inclusion \(V \le U\) of opens in \(C\), the algebra map commutes with restriction: the composition \(k \to \Gamma(C, U) \to \Gamma(C, V)\) equals the direct map \(k \to \Gamma(C, V)\).
99	\end{lemma}
100	
101	\begin{proof}
102	  
103	  \leanok
104	  Both sides factor through the structure morphism map on global sections. The remaining triangle commutes by functoriality of the presheaf on composable inclusions.
105	\end{proof}
106	
107	\begin{lemma}\leanok
108	[Algebra-map naturality]
109	  \label{lem:Scheme_algebraMap_naturality}
110	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.algebraMap_naturality}
111	  \uses{lem:Scheme_algebraMap_eq_kToSection, lem:Scheme_kToSection_naturality}
112	
113	  For any inclusion \(V \le U\) of opens in \(C\) and any \(r \in k\), the restriction map sends the image of \(r\) in \(\Gamma(C, U)\) to the image of \(r\) in \(\Gamma(C, V)\).
114	\end{lemma}
115	
116	\begin{proof}
117	  
118	  \leanok
119	  Lemma~REF reduces both sides to the underlying ring map of the algebra map; Lemma~REF then closes the goal by congruence.
120	\end{proof}
121	
122	\subsection{The presheaf of \(k\)-modules and its sheaf condition}
123	
124	\begin{definition}\leanok
125	[Presheaf of \(k\)-modules from \(\mathcal O_C\)]
126	  \label{def:Scheme_toModuleKPresheaf}
127	  \lean{AlgebraicGeometry.Scheme.toModuleKPresheaf}
128	  \uses{def:Scheme_algebraSection, lem:Scheme_algebraMap_naturality}
129	
130	  Define the presheaf of \(k\)-modules on \(C\) by sending each open \(U\) to the \(k\)-module \(\Gamma(C, U)\), with the \(k\)-action given by the algebra structure of Definition~REF, and on an inclusion \(V \le U\) by the restriction map viewed as a \(k\)-linear map. Functoriality reduces to the presheaf axioms of \(\mathcal O_C\).
131	\end{definition}
132	
133	\begin{theorem}\leanok
134	[Sheaf condition]
135	  \label{thm:Scheme_toModuleKPresheaf_isSheaf}
136	  \lean{AlgebraicGeometry.Scheme.toModuleKPresheaf_isSheaf}
137	  \uses{def:Scheme_toModuleKPresheaf}
138	
139	  The presheaf of Definition~REF is a sheaf for the Grothendieck topology of opens of \(C\).
140	\end{theorem}
141	
142	\begin{proof}
143	  
144	  \leanok
145	  By the concrete-category criterion, it suffices to show that the underlying presheaf of types is a sheaf. By construction, this composite agrees on objects and morphisms with the structure sheaf viewed as a presheaf of types. The latter is a sheaf because the structure sheaf is a sheaf of commutative rings.
146	\end{proof}
147	
148	\subsection{The structure sheaf as a sheaf of \(k\)-modules}
149	
150	\begin{definition}\leanok
151	[Structure sheaf as a sheaf of \(k\)-modules]
152	  \label{def:Scheme_toModuleKSheaf}
153	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf}
154	  \uses{def:Scheme_toModuleKPresheaf, thm:Scheme_toModuleKPresheaf_isSheaf}
155	
156	  Bundle Definition~REF and Theorem~REF into the sheaf of \(k\)-modules on \(C\).
157	\end{definition}
158	
159	\subsection{Forget-and-recover: bridging \(k\)-module and abelian-group values}
160	
161	\begin{definition}\leanok
162	[Forget-and-recover natural iso for the \(k\)-module structure sheaf]
163	  \label{def:Scheme_toModuleKSheaf_forgetCompare}
164	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf_forgetCompare}
165	  \uses{def:Scheme_toModuleKSheaf, def:Scheme_toAbSheaf}
166	
167	  Let \(C\) be a scheme over \(\Spec k\). Then forgetting the \(k\)-module structure from the sheaf of Definition~REF yields a sheaf of abelian groups canonically isomorphic to the abelian-group-valued structure sheaf of Definition~REF.
168	\end{definition}
169	
170	\begin{proof}
171	  
172	  \leanok
173	  Definitionally true: both sides evaluate at every open \(U\) to the abelian group underlying \(\Gamma(C, U)\), and the action on morphisms is the underlying restriction map on both sides.
174	\end{proof}
175	
176	\begin{lemma}\leanok
177	[Object-evaluation lemma for the presheaf of \(k\)-modules]
178	  \label{lem:Scheme_toModuleKPresheaf_obj}
179	  \lean{AlgebraicGeometry.Scheme.toModuleKPresheaf_obj}
180	  \uses{def:Scheme_toModuleKPresheaf}
181	
182	  For every open \(U\) of \(C\), the value of the presheaf of Definition~REF at \(U\) is the \(k\)-module with carrier \(\Gamma(C, U)\).
183	\end{lemma}
184	
185	\begin{proof}
186	  
187	  \leanok
188	  Definitionally true by construction.
189	\end{proof}
190	
191	\section{Sheaf cohomology with \(k\)-module coefficients}
192	\label{sec:HModule}
193	
194	The abstract cohomology API is formulated for sheaves of abelian groups. To obtain a \(k\)-vector-space structure on \(H^n(C, \mathcal O_C)\), we build a parallel sheaf cohomology valued in \(k\)-modules. The sheaf category of \(k\)-modules already has \(\Ext\) (Theorem~REF), and \(\Ext\) groups in any \(k\)-linear abelian category carry a canonical \(k\)-module structure.
195	
196	\begin{definition}\leanok
197	[Sheaf cohomology with \(k\)-module coefficients]
198	  \label{def:Scheme_HModule}
199	  \lean{AlgebraicGeometry.Scheme.HModule}
200	  \uses{thm:HasExt_Sheaf_Opens_ModuleCatK, thm:HasSheafify_Opens_ModuleCatK}
201	
202	  Let \(k\) be a field, \(C\) a Grothendieck site admitting sheafification of \(k\)-modules and \(\Ext\). For a sheaf \(F\) of \(k\)-modules and \(n \in \mathbb N\), define the \(k\)-module-valued sheaf cohomology
203	  \[
204	    H^n_{\Module}(F) \;:=\; \Ext^n\bigl(\text{constant sheaf at }k,\; F\bigr).
205	  \]
206	  This automatically carries a \(k\)-module structure.
207	\end{definition}
208	
209	\begin{remark}[Lean implementation]
210	  The declaration uses a reducible wrapper (`abbrev` rather than `def`) so that instance synthesis sees through to the underlying \(\Ext\) group and finds both the \(k\)-module and abelian-group structures automatically. Under a non-reducible wrapper, `Module.finrank` would fail to typecheck.
211	\end{remark}
212	
213	\section{The \(H^0\) algebraic bridge}
214	\label{sec:HModule_zero}
215	
216	After Definition~REF the cohomology groups \(H^n_{\Module}(F)\) are well-defined and carry the canonical \(k\)-module structure. The next algebraic preliminary is the identification of the degree-zero piece \(H^0_{\Module}(F)\) with a \(\Hom\) group: the bridge from sheaf cohomology to representable Hom-functors.
217	
218	\begin{definition}\leanok
219	[\(H^0\) as a \(k\)-linear Hom group]
220	  \label{def:Scheme_HModule_zero_linearEquiv}
221	  \lean{AlgebraicGeometry.Scheme.HModule_zero_linearEquiv}
222	  \uses{def:Scheme_HModule}
223	
224	  Let \(k\) be a field, \(C\) a Grothendieck site admitting sheafification of \(k\)-modules and \(\Ext\), and \(F\) a sheaf of \(k\)-modules. Then there is a canonical \(k\)-linear equivalence
225	  \[
226	    H^0_{\Module}(F) \;\simeq_k\; \Hom(\text{constant sheaf at }k,\; F).
227	  \]
228	\end{definition}
229	
230	\begin{proof}
231	  
232	  \leanok
233	  Direct from Mathlib's \(H^0\) bridge in any \(k\)-linear abelian category, applied to the sheaf category of \(k\)-modules. The \(k\)-linear enrichment is auto-inferable from the sheafification hypothesis.
234	\end{proof}
235	
236	\begin{remark}[Choice of linear equivalence]
237	  Mathlib provides three flavours of the \(\Ext^0 \simeq \Hom\) equivalence: plain, additive, and \(k\)-linear. We choose the \(k\)-linear refinement because it is the one consumed downstream: finiteness of \(H^0_{\Module}(F)\) over \(k\) is equivalent to finiteness of the Hom group, via transport along a \(k\)-linear equivalence.
238	\end{remark}
239	
240	\section{\v{C}ech cohomology of the structure sheaf}
241	\label{sec:moduleK_cech}
242	
243	This section opens Path~2 of Phase~A step~6: the \v{C}ech-cohomology approach to Serre finiteness. The \v{C}ech complex of a sheaf with respect to an indexed open cover is the standard alternating-coface complex; its cohomology in each degree lives in the category of \(k\)-modules.
244	
245	\begin{definition}\leanok
246	[\v{C}ech complex of the structure sheaf]
247	  \label{def:Scheme_cechCochain_OC}
248	  \lean{AlgebraicGeometry.Scheme.cechCochain_OC}
249	  \uses{def:Scheme_toModuleKSheaf}
250	  Let \(C\) be a scheme over \(\Spec k\) and \(\mathcal U\) an indexed family of opens of \(C\). Define the \v{C}ech cochain complex of the structure sheaf with respect to \(\mathcal U\) to be the standard \v{C}ech complex applied to the underlying presheaf of the \(k\)-module-valued structure sheaf. This is a cochain complex valued in \(k\)-modules, indexed by \(\mathbb N\).
251	\end{definition}
252	
253	\begin{definition}\leanok
254	[\v{C}ech cohomology of the structure sheaf]
255	  \label{def:Scheme_cechCohomology_OC}
256	  \lean{AlgebraicGeometry.Scheme.cechCohomology_OC}
257	  \uses{def:Scheme_cechCochain_OC}
258	  With \((C, \mathcal U)\) as in Definition~REF, define the \(n\)-th \v{C}ech cohomology to be the \(n\)-th homology of the \v{C}ech cochain complex. The result lives in the category of \(k\)-modules.
259	\end{definition}
260	
261	\begin{remark}
262	  This section defines the \v{C}ech carriers but does not prove that \v{C}ech cohomology agrees with derived-functor cohomology. The comparison theorem requires the cover to be acyclic, and is queued for a subsequent iteration.
263	\end{remark}
264	
265	\section{Cohomology of an open in \(k\)-module flavor}
266	\label{sec:hmodule_prime}
267	
268	We introduce a second cohomology carrier: cohomology of an open, parameterised by the open set \(X\). This is the API entry point that downstream Mayer--Vietoris LES and \v{C}ech-vs-derived comparison theorems both consume.
269	
270	\begin{definition}\leanok
271	[Cohomology of an open with \(k\)-module coefficients]
272	  \label{def:Scheme_HModule_prime}
273	  \lean{AlgebraicGeometry.Scheme.HModule'}
